// WebGPU compat test #7 — a REAL aether inference kernel under monster.
//
// This runs aether's Q8_0 dequant-matvec compute shader (the decode-phase
// y[row] = sum_col dequant(W)[row,col] * x[col], W stored as 34-byte GGML Q8_0
// blocks) — copied VERBATIM from
//   open-source/aether/dist-browser/sovereign-shaders.js  (WGSL_MATVEC_Q8_0)
// — on a small KNOWN matrix/vector, and golden-diffs monster's output against
// the Deno real-navigator.gpu oracle (run.mjs canonical-JSON compare).
//
// It exercises everything tests 03/05/06 do NOT in one compute pass:
//   • three storage bindings (read w, read x, read_write y) + a UNIFORM Dims
//   • workgroup shared memory + workgroupBarrier tree reduction
//   • inline f16->f32 decode of the per-block scale + int8 sign-extend
//   • copyBufferToBuffer staging readback of f32 results
//
// monster constraints (see README + test 06): arrays pass BY VALUE; no
// DataView/typed-array bit ops (bytes via the pure-JS f32bytes/f16bytes
// IEEE encoders); buffer SIZES come from CONSTANTS, never concat-loop .length
// (the speculative first pass sees empty loop-built arrays); JSON keys sort.

// f32 -> 4 little-endian bytes (IEEE-754 single), pure JS, identical Deno+monster.
function f32bytes(x) {
  if (x === 0) return [0, 0, 0, 0];
  const sign = x < 0 ? 1 : 0;
  x = Math.abs(x);
  let e = Math.floor(Math.log2(x));
  let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; }
  if (m >= 2) { m /= 2; e += 1; }
  const exp = e + 127;
  const mant = Math.round((m - 1) * Math.pow(2, 23));
  const bits = ((sign << 31) | (exp << 23) | mant) >>> 0;
  return [bits & 0xff, (bits >>> 8) & 0xff, (bits >>> 16) & 0xff, (bits >>> 24) & 0xff];
}
// f32 -> IEEE-754 half (f16) as 2 little-endian bytes. The Q8_0 block scale `d`
// is stored as a half; we restrict callers to values that are EXACTLY half-
// representable (e.g. 0.5, 0.25) so dequant is bit-exact across runtimes and the
// shader's f16_to_f32 decode round-trips it without error.
function f16bytes(x) {
  if (x === 0) return [0, 0];
  const sign = x < 0 ? 1 : 0;
  x = Math.abs(x);
  let e = Math.floor(Math.log2(x));
  let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; }
  if (m >= 2) { m /= 2; e += 1; }
  const exp = e + 15; // half bias
  const mant = Math.round((m - 1) * Math.pow(2, 10)) & 0x3ff;
  const bits = ((sign << 15) | (exp << 10) | mant) & 0xffff;
  return [bits & 0xff, (bits >>> 8) & 0xff];
}
// Decode 4 LE bytes -> f32 (readback assertions).
function bytesToF32(b0, b1, b2, b3) {
  const bits = ((b0) | (b1 << 8) | (b2 << 16) | (b3 << 24)) >>> 0;
  const sign = (bits >>> 31) & 1 ? -1 : 1;
  const exp = (bits >>> 23) & 0xff;
  const mant = bits & 0x7fffff;
  if (exp === 0) return sign * mant * Math.pow(2, -149);
  if (exp === 255) return mant ? NaN : sign * Infinity;
  return sign * (1 + mant / Math.pow(2, 23)) * Math.pow(2, exp - 127);
}
// int8 value -> single byte (two's complement low byte).
function i8byte(q) { return ((q | 0) & 0xff); }

const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();

// ── Known problem: W = ROWS x COLS Q8_0, x = COLS activation ────────────────
// One Q8_0 block = 32 weights, so COLS = 32 keeps it to exactly 1 block/row
// (34 bytes/row) — the smallest honest dequant-matvec. We pick per-row scales
// that are EXACTLY half-representable and small int8 quants so every dequant
// value d*q and the f32 dot product are exact (no tolerance needed).
const ROWS = 2;
const COLS = 32;
const BLOCKS_PER_ROW = COLS / 32;        // 1
const BYTES_PER_ROW = BLOCKS_PER_ROW * 34; // 34
const WORDS_PER_ROW = BYTES_PER_ROW / 2;   // 17 (u16 view? no — wordsPerRow is in u32)
// NB: the shader's wordsPerRow is in u32 WORDS but it's only used as
// rowByteBase = row*wordsPerRow*4, i.e. it must give the per-row BYTE stride/4.
// 34 bytes is not a multiple of 4, so we pad each row's packed bytes up to a u32
// boundary (36 bytes = 9 words) exactly as the engine packs rows word-aligned.
const PADDED_BYTES_PER_ROW = Math.ceil(BYTES_PER_ROW / 4) * 4; // 36
const WORDS_PER_ROW_U32 = PADDED_BYTES_PER_ROW / 4;            // 9

// Row scales (half-exact) and int8 quants.
const scales = [0.5, 0.25];
// quants[row][i], i in 0..31. Keep them small ints.
function qval(row, i) {
  // deterministic, mixed sign, |q| <= 4
  return (((i + row) % 9) - 4); // ranges -4..4
}
// Activation x[col], chosen as exact small f32 values.
function xval(col) { return ((col % 5) - 2) * 0.5; } // -1,-0.5,0,0.5,1 cycle

// Pack weight bytes row-major, each row padded to PADDED_BYTES_PER_ROW.
let wBytes = [];
for (let row = 0; row < ROWS; row++) {
  let rb = [];
  rb = rb.concat(f16bytes(scales[row])); // scale d (2 bytes)
  for (let i = 0; i < 32; i++) rb = rb.concat([i8byte(qval(row, i))]); // 32 int8
  // pad row to PADDED_BYTES_PER_ROW
  while (rb.length < PADDED_BYTES_PER_ROW) rb = rb.concat([0]);
  wBytes = wBytes.concat(rb);
}
const W_BYTES_TOTAL = ROWS * PADDED_BYTES_PER_ROW; // 72

// Activation bytes.
let xBytes = [];
for (let c = 0; c < COLS; c++) xBytes = xBytes.concat(f32bytes(xval(c)));
const X_BYTES_TOTAL = COLS * 4; // 128

// Dims uniform: rows, cols, blocksPerRow, wordsPerRow, dispatchRowsX (5 x u32).
let dimBytes = [];
function u32bytes(v) { return [v & 0xff, (v >>> 8) & 0xff, (v >>> 16) & 0xff, (v >>> 24) & 0xff]; }
dimBytes = dimBytes
  .concat(u32bytes(ROWS))
  .concat(u32bytes(COLS))
  .concat(u32bytes(BLOCKS_PER_ROW))
  .concat(u32bytes(WORDS_PER_ROW_U32))
  .concat(u32bytes(ROWS)); // dispatchRowsX
const DIM_BYTES_TOTAL = 5 * 4; // 20

const Y_BYTES_TOTAL = ROWS * 4; // 8

// ── Buffers ─────────────────────────────────────────────────────────────────
const wBuf = device.createBuffer({ size: W_BYTES_TOTAL, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(wBuf, 0, new Uint8Array(wBytes));
const xBuf = device.createBuffer({ size: X_BYTES_TOTAL, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(xBuf, 0, new Uint8Array(xBytes));
const yBuf = device.createBuffer({ size: Y_BYTES_TOTAL, usage: GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_SRC });
const dBuf = device.createBuffer({ size: DIM_BYTES_TOTAL, usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(dBuf, 0, new Uint8Array(dimBytes));

// ── Shader: WGSL_MATVEC_Q8_0 copied verbatim from sovereign-shaders.js ──────
const shader = device.createShaderModule({
  code: `
fn f16_to_f32(h: u32) -> f32 {
  let sign = (h >> 15u) & 1u;
  let exp  = (h >> 10u) & 0x1Fu;
  let frac = h & 0x3FFu;
  var val: f32;
  if (exp == 0u) {
    val = (f32(frac) / 1024.0) * 0.00006103515625;
  } else if (exp == 0x1Fu) {
    val = select(3.0e38, 0.0, frac != 0u);
  } else {
    val = (1.0 + f32(frac) / 1024.0) * exp2(f32(i32(exp) - 15));
  }
  return select(val, -val, sign == 1u);
}
fn s8(b: u32) -> i32 { return (i32(b) << 24) >> 24; }

struct Dims { rows: u32, cols: u32, blocksPerRow: u32, wordsPerRow: u32, dispatchRowsX: u32 };
@group(0) @binding(0) var<storage, read> w: array<u32>;
@group(0) @binding(1) var<storage, read> x: array<f32>;
@group(0) @binding(2) var<storage, read_write> y: array<f32>;
@group(0) @binding(3) var<uniform> d: Dims;

fn wbyte(off: u32) -> u32 {
  let word = w[off >> 2u];
  let shift = (off & 3u) * 8u;
  return (word >> shift) & 0xFFu;
}

var<workgroup> partial: array<f32, 64>;

@compute @workgroup_size(64, 1, 1)
fn main(@builtin(workgroup_id) wid: vec3<u32>, @builtin(local_invocation_id) lid: vec3<u32>) {
  let row = wid.x + wid.y * d.dispatchRowsX;
  let tid = lid.x;
  if (row >= d.rows) { return; }
  let rowByteBase = row * d.wordsPerRow * 4u;
  var acc: f32 = 0.0;
  var b: u32 = tid;
  loop {
    if (b >= d.blocksPerRow) { break; }
    let blockBase = rowByteBase + b * 34u;
    let scale = f16_to_f32(wbyte(blockBase) | (wbyte(blockBase + 1u) << 8u));
    let qbase = blockBase + 2u;
    let col = b * 32u;
    for (var i: u32 = 0u; i < 32u; i = i + 1u) {
      let q = s8(wbyte(qbase + i));
      acc = acc + scale * f32(q) * x[col + i];
    }
    b = b + 64u;
  }
  partial[tid] = acc;
  workgroupBarrier();
  var stride: u32 = 32u;
  loop {
    if (stride == 0u) { break; }
    if (tid < stride) { partial[tid] = partial[tid] + partial[tid + stride]; }
    workgroupBarrier();
    stride = stride >> 1u;
  }
  if (tid == 0u) { y[row] = partial[0]; }
}
`,
});
const pipeline = device.createComputePipeline({ layout: 'auto', compute: { module: shader, entryPoint: 'main' } });
const bindGroup = device.createBindGroup({
  layout: pipeline.getBindGroupLayout(0),
  entries: [
    { binding: 0, resource: { buffer: wBuf } },
    { binding: 1, resource: { buffer: xBuf } },
    { binding: 2, resource: { buffer: yBuf } },
    { binding: 3, resource: { buffer: dBuf } },
  ],
});

const enc = device.createCommandEncoder();
const pass = enc.beginComputePass();
pass.setPipeline(pipeline);
pass.setBindGroup(0, bindGroup);
pass.dispatchWorkgroups(ROWS, 1, 1); // one workgroup per output row
pass.end();

const readBuf = device.createBuffer({ size: Y_BYTES_TOTAL, usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ });
enc.copyBufferToBuffer(yBuf, 0, readBuf, 0, Y_BYTES_TOTAL);
device.queue.submit([enc.finish()]);

await readBuf.mapAsync(GPUMapMode.READ);
const px = new Uint8Array(readBuf.getMappedRange());
let result = [];
for (let r = 0; r < ROWS; r++) {
  const o = r * 4;
  result = result.concat([bytesToF32(px[o], px[o + 1], px[o + 2], px[o + 3])]);
}
readBuf.unmap();

// Independent CPU reference (same dequant-matvec) so the JSON also records the
// arithmetic truth, not just runtime-vs-runtime agreement.
let cpu = [];
for (let r = 0; r < ROWS; r++) {
  let acc = 0;
  for (let i = 0; i < 32; i++) acc += scales[r] * qval(r, i) * xval(i);
  cpu = cpu.concat([acc]);
}

// f32 GPU goldens differ in the last ULP across backends (Deno-wgpu vs
// monster-wgpu may pick different fma/accumulation codegen) — e.g. row 0 reads
// -2.499999761581421 on one and -2.499999523162842 on the other; both are -2.5.
// The harness does EXACT JSON compare, so we quantize the reported result to a
// tolerance band (1e-4) that absorbs sub-ULP backend disagreement yet would
// still flag any real dequant/matvec bug (those move whole units). The raw
// values are logged to stderr for the record so nothing is hidden.
function q(v) { return Math.round(v * 1e4) / 1e4; }
console.error('RAW gpu=' + JSON.stringify(result) + ' cpu=' + JSON.stringify(cpu));
out.gpu = result.map(q);
out.cpu = cpu.map(q);
console.log('__RESULT__ ' + JSON.stringify(out));
